        v_real_10luk = 29.78 # km/s
        hiz_sabiti = 1.061 # Simule Hiz Sabiti
        # 11'lik Zaman: 66sn * 66dk * 22sa * 363gun
        # 66 * 66 * 22 = 95,832 saniye (bir gun)
