        carpim = self.FARK * self.OMURGA * self.TOPLAM
        cap_izdusumu = carpim / 10.0
        fiziksel_cap_kodu = cap_izdusumu - self.FARK
        sapma = abs(fiziksel_cap_kodu - self.GERCEK_EKVATOR_CAPI)
        return carpim, cap_izdusumu, fiziksel_cap_kodu, sapma

