        self.HICRI_KAYMA = 11.0            # 365 - 354 (YÃ„Â±llÃ„Â±k 11 gÃƒÂ¼n kayma)
        self.KUSURSUZ_DONGU_YILI = 33      # Hayyam ve Hicri kilit noktasÃ„Â±

