        """33 YÃ„Â±llÃ„Â±k 2.2424 sapmasÃ„Â±nÃ„Â±n Halley (74) ve Uzay (814) sabitini vermesi"""
        birikmis_sapma = self.KUSURSUZ_DONGU_YILI * self.ZAMAN_SAPMASI
        uzay_kilidi_1 = round(birikmis_sapma) * 11
        uzay_kilidi_2 = self.IDEAL_YIL * self.ZAMAN_SAPMASI
