        self.HACIM_KATI = 1.083
        self.IDEAL_HACIM = 1.331
        self.HACIM_SIVI_MATRIS = 1.332
        self.HACIM_SIVI_1332 = 1332.0
        self.DUNYA_KUTLE = 5.972

