    def karekok_22_matrisi(self):
        return math.sqrt(self.GEOIT_FARK) + math.sqrt(self.OMURGA) + math.sqrt(self.GEOIT_TOPLAM)

    def hiz_hacim_1111_ispat(self):
        saf_matris = self.HACIM_SIVI_1332 - self.GALAKTIK_HIZ
