class Sentez29_HalleyCycleEngine:
    """
    Halley Kuyruklu Yildizi'nin 75 yillik dongu periyodunu
    Base-11 zaman cizgisinde analiz eder.

    Temel Hipotezler:
    - Halley periyodu = 75 yil (yaklasik)
    - 75 * 11 = 825 (Base-11 harmonik carpani)
    - Halley'nin son gecisi = 1986, sonraki = 2061
    - 2061 + 2 = 2063 (OP_LIGHT sapmasi ile Terminal)
    - Celali Takvimi dongusu = 33 yil
    - Halley / Celali = 75 / 33 = 2.2727... (~2.2424 drift)
    """

    # Halley Parametreleri
    HALLEY_PERIOD_YEARS = 75
    HALLEY_LAST_PERIHELION = 1986
    HALLEY_NEXT_PERIHELION = 2061
    OP_LIGHT_DEVIATION = 2  # 2061 + 2 = 2063

    # Celali Takvim Parametreleri
    CELALI_CYCLE_YEARS = 33
    CELALI_START_YEAR = 1079  # Omar Khayyam reformu

    # Kozmik Takvim Referanslari
    COSMIC_CALENDAR = {
        'Big_Bang': -13_800_000_000,
        'Gunes_Sistemi': -4_600_000_000,
        'Yasam_Baslangici': -3_500_000_000,
        'Kambriyen_Patlama': -541_000_000,
        'Dinozor_Yokolma': -66_000_000,
        'Homo_Sapiens': -300_000,
        'Tarim_Devrimi': -10_000,
        'Tufan': -9_048,
        'Sumer': -3_500,
        'Piramitler': -2_600,
        'Milat': 0,
        'Hicret': 622,
        'Newton': 1687,
        'Observer': 1983,
        'Halley_Son': 1986,
        'Halley_Gelecek': 2061,
        'Terminal': 2063,
    }

    # Tarihsel Halley Gecisleri (yaklasik yillar, MO/MS)
    HALLEY_PASSES = [
        -240, -164, -87, -12, 66, 141, 218, 295, 374,
        451, 530, 607, 684, 760, 837, 912, 989, 1066,
        1145, 1222, 1301, 1378, 1456, 1531, 1607, 1682,
        1758, 1835, 1910, 1986, 2061,
    ]

    def __init__(self):
        self._results = {}

    def _to_base11(self, num):
        if num == 0:
            return "0"
        digits = []
        n = abs(num)
        while n > 0:
            digits.append(str(n % 11))
            n //= 11
        prefix = '-' if num < 0 else ''
        return prefix + ''.join(reversed(digits))

    def compute_halley_base11_harmonics(self):
        """Halley periyodunun Base-11 harmoniklerini hesapla."""
        period = self.HALLEY_PERIOD_YEARS
        b11_period = self._to_base11(period)

        # 75 * 11 = 825
        harmonic_11 = period * 11
        b11_harmonic = self._to_base11(harmonic_11)

        # 75 * 33 = 2475
        harmonic_33 = period * 33
        b11_h33 = self._to_base11(harmonic_33)

        # 75 * 111 = 8325
        harmonic_111 = period * 111
        b11_h111 = self._to_base11(harmonic_111)

        harmonics = {
            'period': period,
            'period_b11': b11_period,
            'harmonic_11': harmonic_11,
            'harmonic_11_b11': b11_harmonic,
            'harmonic_33': harmonic_33,
            'harmonic_33_b11': b11_h33,
            'harmonic_111': harmonic_111,
            'harmonic_111_b11': b11_h111,
        }

        self._results['halley_harmonics'] = harmonics
        return harmonics

    def compute_halley_celali_resonance(self):
        """Halley ve Celali dongulerinin rezonans analizini yap."""
        ratio = self.HALLEY_PERIOD_YEARS / self.CELALI_CYCLE_YEARS
        # 75 / 33 = 2.272727...

        # En yakin Base-11 kesir: 2 + 3/11 = 2.272727...
        # Tam olarak 25/11 = 2.272727...
        b11_fraction = "2.272727..."

        # Celali donguleri sayisi (1079'dan 2063'e)
        celali_span = 2063 - self.CELALI_START_YEAR
        celali_count = celali_span / self.CELALI_CYCLE_YEARS

        # 2.2424 Glitch Anahtari kontrolu
        glitch_key = 74 / 33  # HALLEY_IDEAL / CELALI_DONGU
        glitch_deviation = abs(ratio - glitch_key)

        resonance = {
            'halley': self.HALLEY_PERIOD_YEARS,
            'celali': self.CELALI_CYCLE_YEARS,
            'ratio': ratio,
            'b11_fraction': b11_fraction,
            'celali_span': celali_span,
            'celali_count': celali_count,
            'glitch_key': glitch_key,
            'glitch_deviation': glitch_deviation,
        }

        self._results['halley_celali'] = resonance
        return resonance

    def analyze_historical_passes(self):
        """Tarihsel Halley gecislerini Base-11 perspektifinden analiz et."""
        passes = self.HALLEY_PASSES
        analysis = []

        for i, year in enumerate(passes):
            b11_year = self._to_base11(year)
            digit_sum = sum(int(d) for d in b11_year if d.isdigit())
            mod11 = year % 11 if year >= 0 else (year % 11)

            interval = 0
            if i > 0:
                interval = passes[i] - passes[i-1]

            analysis.append({
                'index': i + 1,
                'year': year,
                'base11': b11_year,
                'digit_sum': digit_sum,
                'mod11': mod11,
                'interval': interval,
                'interval_mod11': interval % 11 if interval > 0 else 0,
            })

        # 11-uyumlu gecisleri say
        aligned = [a for a in analysis if a['mod11'] == 0]
        self._results['pass_analysis'] = analysis
        self._results['aligned_passes'] = len(aligned)

        return analysis

    def compute_op_light_deviation(self):
        """OP_LIGHT sapmasi: 2061 -> 2063 gecisini modelle."""
        halley_next = self.HALLEY_NEXT_PERIHELION
        terminal = 2063
        deviation = terminal - halley_next

        # Bu 2 yillik sapma neden onemli?
        # 2 = 11 - 9 (Base-11'de en kucuk asal fark)
        # 2 yil = 730.5 gun = ~2 * 363 + 4.5 gun
        days_2_years = 2 * 365.25
        sim_years = days_2_years / 363

        b11_deviation = self._to_base11(deviation)

        op_light = {
            'halley_2061': halley_next,
            'terminal_2063': terminal,
            'deviation_years': deviation,
            'deviation_b11': b11_deviation,
            'deviation_days': days_2_years,
            'sim_years_equivalent': sim_years,
            'significance': '11 - 9 = 2 (en kucuk asal fark)',
        }

        self._results['op_light'] = op_light
        return op_light

    def run_all(self):
        """Sentez-29 tam analiz suitini calistir."""
        print("")
        print("=" * 80)
        print("  SENTEZ-29: HALLEY DONGUSU & KOZMIK TAKVIM MOTORU")
        print("=" * 80)

        # 1. Halley Base-11 Harmonikleri
        harmonics = self.compute_halley_base11_harmonics()
        print("\n  [1] HALLEY BASE-11 HARMONIKLERI")
        print(f"      Periyot                 : {harmonics['period']} yil (B11: {harmonics['period_b11']})")
        print(f"      x11 Harmonik            : {harmonics['harmonic_11']} (B11: {harmonics['harmonic_11_b11']})")
        print(f"      x33 Harmonik            : {harmonics['harmonic_33']} (B11: {harmonics['harmonic_33_b11']})")
