within_class = False

# Things that definitively mean a class has ended if found at col 0
CLASS_STOPPERS = ['try:', 'import ', 'from ', '# =', '# -', 'if __name__', 'GEN_LANG', 'ROCHE_', 'def ai_status_report', '_GENERAVITY']

for i in range(len(lines)):
    if i <= skip_until:
        continue
        
    line = lines[i]
